mapper.update:
MERGE INTO TBL_STOCK_TAKE AS T USING ( SELECT CONVERT(VARCHAR(8), GETDATE(), 112) AS TAKE_DATE, #{locCd} AS LOC_CD, #{mtrlCd} AS MTRL_CD, #{pltSize} AS PLT_SIZE ) AS S ON (T.TAKE_DATE = S.TAKE_DATE AND T.LOC_CD = S.LOC_CD AND T.MTRL_CD = S.MTRL_CD AND T.PLT_SIZE = S.PLT_SIZE)
WHEN MATCHED THEN UPDATE SET T.QTY = #{qty}, T.REG_TIME = GETDATE()
WHEN NOT MATCHED THEN INSERT (TAKE_DATE, LOC_CD, MTRL_CD, PLT_SIZE, QTY, REG_TIME, APPLY_YN) VALUES (CONVERT(VARCHAR(8), GETDATE(), 112), #{locCd}, #{mtrlCd}, #{pltSize}, #{qty}, GETDATE(), 'N');

mapper.select:
SELECT TOP 1 MTRL_CD, MTRL_NM
FROM TBL_MTRL_M
WHERE MTRL_CD = #{barcode} OR BARCODE = #{barcode}
